async function loadLocation(){try{const t=await fetch("/assets/components/location.html"),e=await t.text(),n=document.getElementById("location-placeholder"),a=n.dataset.title,o=n.dataset.venueDetails,d=n.dataset.parkingDetails,i=n.dataset.transportDetails,l=n.dataset.map;n.innerHTML=e,a&&(document.getElementById("location-title").innerText=a),document.getElementById("venue-details").innerText=o,d?document.getElementById("parking-details").innerText=d:document.getElementById("parking-section").style.display="none",i?document.getElementById("transport-details").innerText=i:document.getElementById("transport-section").style.display="none",document.getElementById("map-frame").src=l}catch(t){console.error("Error loading location:",t)}}document.addEventListener("DOMContentLoaded",loadLocation);